function toIso(value) {
  return value instanceof Date ? value.toISOString() : String(value);
}

async function readFactsFromDb(db) {
  const account = (await db.query("SELECT * FROM accounts LIMIT 1")).rows[0];
  const normalizeNumbers = (rows, field) =>
    rows.map((row) => ({
      ...row,
      [field]: row[field] == null ? row[field] : Number(row[field])
    }));

  const invoices = normalizeNumbers(
    (await db.query("SELECT invoice_id, amount_cents, due_date, status FROM invoices")).rows,
    "amount_cents"
  ).map((invoice) => ({
    invoiceId: invoice.invoice_id,
    amountCents: invoice.amount_cents,
    dueDate: toIso(invoice.due_date),
    status: invoice.status
  }));

  const shipments = (await db.query("SELECT shipment_id, sla_date, delivered_date, status FROM shipments")).rows.map((shipment) => ({
    shipmentId: shipment.shipment_id,
    slaDate: toIso(shipment.sla_date),
    deliveredDate: shipment.delivered_date ? toIso(shipment.delivered_date) : null,
    status: shipment.status
  }));

